def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        base_score = 0
        if ratio == 1:
            base_score = 0
        elif ratio < 0.3:
            base_score = (0.3 - ratio) ** 3 + 0.2
        elif 0.3 <= ratio < 0.6:
            base_score = abs(np.sin(np.pi * ratio)) * 0.7
        else:
            try:
                base_score = abs(np.log(ratio)) * (1 + (i % 5) * 0.15)
            except:
                base_score = 1.0
        neighbor_sum = 0
        weight_total = 0
        for j in range(1, 6):
            for neighbor_idx in [i - j, i + j]:
                if 0 <= neighbor_idx < n:
                    neighbor_capacity = bins[neighbor_idx]
                    if neighbor_capacity > 0:
                        diff_ratio = abs(capacity - neighbor_capacity) / neighbor_capacity
                        neighbor_weight = 1 / j
                        neighbor_sum += diff_ratio * neighbor_weight
                        weight_total += neighbor_weight
        if weight_total > 0:
            neighbor_avg = neighbor_sum / weight_total
        else:
            neighbor_avg = 0
        adj_score = base_score + neighbor_avg * 0.1
        if ratio > 0.85:
            adj_score *= 0.8
        elif ratio < 0.4:
            adj_score *= 1.2
        if i % 2 == 0 and ratio > 0.5:
            adj_score *= 0.9
        if item > 5 and capacity > 10:
            for k in range(1, 4):
                idx_offset = i + ((-1) ** k) * k
                if 0 <= idx_offset < n and bins[idx_offset] > 0:
                    adj_score += abs(capacity - bins[idx_offset]) * 0.01 * k
        priorities[i] = max(adj_score, 0)
    min_priority = np.min(priorities[np.isfinite(priorities)])
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority * 10
    return priorities
